// nodes/BaseNode.js
import { Handle, Position } from 'reactflow';
import { motion } from 'framer-motion';
import clsx from 'clsx';

export const BaseNode = ({
  id,
  title,
  icon: Icon,
  accentColor = 'var(--accent-blue)',
  inputs = [],
  outputs = [],
  children,
  style = {},
  selected = false,
}) => {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      className={clsx('base-node', selected && 'selected')}
      style={{
        minWidth: 200,
        background: 'var(--bg-surface)',
        border: '1px solid var(--border-subtle)',
        borderRadius: '12px',
        boxShadow: selected 
          ? `0 0 0 2px ${accentColor}, 0 12px 32px rgba(0,0,0,0.5)` 
          : '0 8px 24px rgba(0,0,0,0.4)',
        position: 'relative',
        transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
        ...style,
      }}
    >
      {/* Node Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '10px',
          padding: '12px 16px',
          borderBottom: '1px solid var(--border-subtle)',
          borderTopLeftRadius: '12px',
          borderTopRightRadius: '12px',
          background: 'var(--bg-surface-elevated)',
        }}
      >
        <div 
          style={{ 
            color: accentColor,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: `${accentColor}1A`, // 10% opacity
            padding: '6px',
            borderRadius: '6px',
          }}
        >
          {Icon && <Icon size={16} strokeWidth={2.5} />}
        </div>
        <span
          style={{
            fontSize: '13px',
            fontWeight: 600,
            color: 'var(--text-primary)',
          }}
        >
          {title}
        </span>
      </div>

      {/* Body Content (Read-only previews) */}
      {children && (
        <div style={{ padding: '12px 16px' }}>
          {children}
        </div>
      )}

      {/* Handles */}
      {inputs.map((handle, i) => {
        const top = inputs.length === 1
          ? '50%'
          : `${20 + (handle.position ?? i / (inputs.length - 1)) * 60}%`;
        return (
          <div key={handle.id}>
            <Handle
              type="target"
              position={Position.Left}
              id={handle.id}
              style={{
                top,
                left: -7,
                width: 14,
                height: 14,
                background: 'var(--bg-surface)',
                border: `2px solid ${accentColor}`,
                borderRadius: '50%',
                transition: 'all 0.2s',
              }}
            />
          </div>
        );
      })}

      {outputs.map((handle, i) => {
        const top = outputs.length === 1
          ? '50%'
          : `${20 + (handle.position ?? i / (outputs.length - 1)) * 60}%`;
        return (
          <div key={handle.id}>
            <Handle
              type="source"
              position={Position.Right}
              id={handle.id}
              style={{
                top,
                right: -7,
                width: 14,
                height: 14,
                background: 'var(--bg-surface)',
                border: `2px solid ${accentColor}`,
                borderRadius: '50%',
                transition: 'all 0.2s',
              }}
            />
          </div>
        );
      })}
    </motion.div>
  );
};
